// ==================== 🔒 防連點 Hook ====================
function useLock(ms = 800) {
  const locked = useRef(false);
  const lockFn = useCallback((fn) => (...args) => {
    if (locked.current) return;
    locked.current = true;
    fn(...args);
    setTimeout(() => { locked.current = false; }, ms);
  }, [ms]);
  return lockFn;
}

// ==================== 🎵 音效系統 ====================
const SFX = {
  ctx: null,
  muted: false,
  init() { if (!this.ctx) try { this.ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch {} },
  play(freq, dur = 0.15, type = "sine") {
    if (this.muted) return;
    try {
      this.init();
      if (!this.ctx) return;
      const o = this.ctx.createOscillator();
      const g = this.ctx.createGain();
      o.connect(g); g.connect(this.ctx.destination);
      o.type = type; o.frequency.value = freq;
      g.gain.setValueAtTime(0.15, this.ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + dur);
      o.start(); o.stop(this.ctx.currentTime + dur);
    } catch {}
  },
  click() { this.play(800, 0.08); },
  success() { this.play(523, 0.12); setTimeout(() => this.play(659, 0.12), 120); setTimeout(() => this.play(784, 0.2), 240); },
  fail() { this.play(300, 0.2, "square"); },
  spin() { let i=0; const t=setInterval(()=>{this.play(400+i*30,0.06);i++;if(i>15)clearInterval(t);},100); },
  fanfare() { [523,659,784,1047].forEach((f,i) => setTimeout(()=>this.play(f,0.3),i*200)); },
};

