const FlowerPetals = ({ count = 30 }) => {
  const petals = useMemo(() => Array.from({ length: count }, (_, i) => {
    const colors = ["#f9a8d4","#fbcfe8","#f472b6","#c084fc","#a78bfa","#e9d5ff","#fda4af","#fecdd3","#86efac","#bbf7d0"];
    return { id: i, x: Math.random()*100, size: Math.random()*10+6, dur: Math.random()*6+5, delay: Math.random()*8, color: colors[Math.floor(Math.random()*colors.length)], rot: Math.random()*360 };
  }), [count]);
  return <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">{petals.map(p => <div key={p.id} className="absolute" style={{ left:`${p.x}%`, top:`-${p.size}px`, width:p.size, height:p.size*0.7, backgroundColor:p.color, borderRadius:"50% 0 50% 50%", opacity:0.7, transform:`rotate(${p.rot}deg)`, animation:`petalFall ${p.dur}s ease-in-out ${p.delay}s infinite`, filter:"blur(0.5px)" }} />)}</div>;
};

// ==================== ⌨️ 打字機 ====================
const TW = ({ text, speed = 45, onComplete, className = "" }) => {
  const [d, setD] = useState(""); const [done, setDone] = useState(false); const r = useRef(0);
  useEffect(() => { setD(""); setDone(false); r.current = 0;
    const t = setInterval(() => { r.current++; if (r.current <= text.length) setD(text.slice(0, r.current)); else { clearInterval(t); setDone(true); onComplete?.(); } }, speed);
    return () => clearInterval(t);
  }, [text, speed]);
  return <span className={className}>{d}{!done && <span className="animate-pulse text-amber-400">▌</span>}</span>;
};

// ==================== 💬 對話框 ====================
const DBox = ({ lines, onComplete }) => {
  const [li, setLi] = useState(0); const [td, setTd] = useState(false); const [ad, setAd] = useState(false);
  const l = lines[li]; const last = li >= lines.length - 1;
  const next = () => { vibrate(30); SFX.click(); if (!td) { setTd(true); return; } if (last) { setAd(true); onComplete?.(); } else { setLi(i=>i+1); setTd(false); } };
  if (ad) return null;
  const sc = { narrator: { n:"旁白", c:"text-gray-400", img:null }, bird: { n:"阿啾", c:"text-yellow-300", img: getBirdImg(l.mood||"happy") }, bride: { n:CONFIG.BRIDE, c:"text-pink-300", img: l.img||IMG_BRIDE_SOLO }, groom: { n:CONFIG.GROOM, c:"text-blue-300", img: l.img||IMG_GROOM_SOLO } };
  const sp = sc[l.speaker] || sc.narrator;
  return (
    <div className="w-full animate-fi" onClick={next}>
      {sp.img && <div className="flex justify-center mb-3"><img src={sp.img} alt={sp.n} className="w-28 h-28 object-contain" style={{ filter:"drop-shadow(0 0 10px rgba(251,191,36,0.3))" }} /></div>}
      <div className="relative border border-amber-400/30 rounded-xl bg-black/50 backdrop-blur-sm p-4">
        <div className="absolute -top-3 left-4"><span className={`text-xs font-bold px-3 py-1 rounded-full bg-black/80 border border-amber-400/40 ${sp.c}`}>{sp.n}</span></div>
        <div className="mt-2 min-h-[3rem]">{td ? <p className="text-white/85 text-sm leading-relaxed">{l.text}</p> : <TW text={l.text} speed={40} onComplete={()=>setTd(true)} className="text-white/85 text-sm leading-relaxed" />}</div>
        <div className="text-right mt-1"><span className="text-amber-400/60 text-xs animate-pulse">{li===0&&!td?"👆 點擊畫面繼續":last&&td?"▶ 繼續":"▼ 點擊繼續"}</span></div>
      </div>
    </div>
  );
};

