            <div className={`text-6xl mb-3 ${adv.team==="blue"?"drop-shadow-[0_0_20px_rgba(59,130,246,0.9)]":"drop-shadow-[0_0_20px_rgba(239,68,68,0.9)]"}`}>{adv.team==="blue"?"🔵":"🔴"}</div>
