// ==================== 📝 第三關（含答錯顯示正確答案） ====================
const Stage3 = ({ adv }) => {
  const [ph, setPh] = useState(adv.dd?"quiz":"dialogue"); const [sel, setSel] = useState(null); const [ans, setAns] = useState(false); const [cor, setCor] = useState(false); const [sh, setSh] = useState(false);
  useEffect(()=>{setTimeout(()=>setSh(true),200);},[]);
  const q = CONFIG.QUIZ_QUESTIONS[adv.qi];
  // Guard: if qi is out of bounds (corrupted state), go to finale
  useEffect(() => { if (!q) adv.set({ stage: "ftrans", dd: false }); }, []);
  const doAns = (i)=>{if(ans || !q)return;setSel(i);setAns(true);const ok=i===q.answer;setCor(ok);vibrate(ok?[30,30,30]:150);ok?SFX.success():SFX.fail();if(ok)adv.set({qo:adv.qo+1});};
  const nxt = ()=>{const n=adv.qi+1;if(n>=CONFIG.QUIZ_QUESTIONS.length)adv.set({stage:"ftrans",dd:false});else{adv.set({qi:n});setSel(null);setAns(false);setCor(false);}};
  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-5 transition-opacity duration-700 ${sh?"opacity-100":"opacity-0"}`}>
      <Particles color="#34d399" count={18}/><Progress current={3} total={4} team={adv.team}/>
      <ChTitle ch="Chapter 3" title="時光迴廊" sub="12 年的點點滴滴" g="from-emerald-300 to-teal-200"/>
      <Card className="w-full max-w-sm relative z-10" team={adv.team} glow>
        {ph==="dialogue"&&<DBox lines={CONFIG.STORY.stage3} onComplete={()=>{setPh("quiz");adv.set({dd:true});}}/>}
        {ph==="quiz"&&q&&<div className="space-y-4">
          <div className="flex items-center justify-between"><div className="flex items-center gap-2"><img src={ans?(cor?IMG_BIRD_HAPPY:IMG_BIRD_ANGRY):IMG_BIRD_THINK} alt="阿啾" className="w-12 h-12 object-contain"/><span className="text-xs text-white/40 font-mono">{adv.qi+1}/{CONFIG.QUIZ_QUESTIONS.length}</span></div><span className="text-xs text-white/40">✅ {adv.qo}</span></div>
          <p className="text-white text-base font-bold text-center py-1">{q.question}</p>
          <div className="space-y-2">{q.options.map((o,i)=>{let c="bg-white/5 border-white/10 hover:bg-white/10 text-white/80";if(ans){if(i===q.answer)c="bg-green-500/20 border-green-400/50 text-green-300";else if(i===sel)c="bg-red-500/20 border-red-400/50 text-red-300";else c="bg-white/5 border-white/5 text-white/25";}return (<button key={i} onClick={()=>doAns(i)} disabled={ans} className={`w-full text-left px-4 py-3 rounded-lg border text-sm transition-all ${c} disabled:cursor-default`}><span className="font-mono text-xs mr-2 opacity-40">{String.fromCharCode(65+i)}.</span>{o}</button>);})}</div>
          {ans&&<div className="space-y-2 animate-fi pt-1">
            <p className={`text-center text-sm font-bold ${cor?"text-green-400":"text-red-400"}`}>{cor?"🎉 答對了！":"😅 答錯囉～"}</p>
            {!cor&&<p className="text-center text-xs text-amber-300/70">正確答案：<span className="font-bold">{q.options[q.answer]}</span></p>}
            <Btn onClick={nxt} team={adv.team}>{adv.qi+1>=CONFIG.QUIZ_QUESTIONS.length?"前往結局 →":"下一題 →"}</Btn>
          </div>}
        </div>}
      </Card>
    </div>);
};

// ==================== 🏆 結局（含截圖分享+成就） ====================
